import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  Box, 
  Button, 
  Card, 
  CardContent, 
  CircularProgress, 
  Container, 
  Grid, 
  Paper, 
  Typography,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Alert,
  Divider,
  Chip,
  IconButton,
  Fade,
  Skeleton
} from '@mui/material';
import RefreshIcon from '@mui/icons-material/Refresh';
import DeleteIcon from '@mui/icons-material/Delete';
import DescriptionIcon from '@mui/icons-material/Description';
import PublicIcon from '@mui/icons-material/Public';
import BadgeIcon from '@mui/icons-material/Badge';
import PassportIcon from '@mui/icons-material/ArticleOutlined';
import DownloadIcon from '@mui/icons-material/Download';
import InfoIcon from '@mui/icons-material/Info';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Title,
  Legend,
  ArcElement
} from 'chart.js';
import { Bar, Pie } from 'react-chartjs-2';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement
);

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchStats = async () => {
    setLoading(true);
    try {
      const response = await axios.get('http://localhost:5001/api/stats');
      setStats(response.data);
      setError(null);
    } catch (err) {
      setError('Error fetching statistics: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const resetStats = async () => {
    setLoading(true);
    try {
      await axios.post('http://localhost:5001/api/reset-stats');
      fetchStats();
    } catch (err) {
      setError('Error resetting statistics: ' + err.message);
    }
  };

  useEffect(() => {
    fetchStats();
  }, []);

  // Prepare chart data for document types
  const documentTypeChartData = {
    labels: stats?.document_types ? Object.keys(stats.document_types).map(type => type.charAt(0).toUpperCase() + type.slice(1)) : [],
    datasets: [
      {
        label: 'Document Types',
        data: stats?.document_types ? Object.values(stats.document_types) : [],
        backgroundColor: [
          'rgba(54, 162, 235, 0.6)',
          'rgba(255, 99, 132, 0.6)',
          'rgba(255, 206, 86, 0.6)',
        ],
        borderColor: [
          'rgba(54, 162, 235, 1)',
          'rgba(255, 99, 132, 1)',
          'rgba(255, 206, 86, 1)',
        ],
        borderWidth: 1,
      },
    ],
  };

  // Prepare chart data for nationalities
  const nationalitiesChartData = {
    labels: stats?.nationalities ? Object.keys(stats.nationalities) : [],
    datasets: [
      {
        label: 'Nationalities',
        data: stats?.nationalities ? Object.values(stats.nationalities) : [],
        backgroundColor: [
          'rgba(75, 192, 192, 0.6)',
          'rgba(153, 102, 255, 0.6)',
          'rgba(255, 159, 64, 0.6)',
          'rgba(255, 99, 132, 0.6)',
          'rgba(54, 162, 235, 0.6)',
          'rgba(255, 206, 86, 0.6)',
        ],
        borderColor: [
          'rgba(75, 192, 192, 1)',
          'rgba(153, 102, 255, 1)',
          'rgba(255, 159, 64, 1)',
          'rgba(255, 99, 132, 1)',
          'rgba(54, 162, 235, 1)',
          'rgba(255, 206, 86, 1)',
        ],
        borderWidth: 1,
      },
    ],
  };

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Box>
          <Typography variant="h4" component="div" sx={{ display: 'flex', alignItems: 'center' }}>
            <DescriptionIcon sx={{ mr: 1, fontSize: 32 }} /> 
            Document Scanner Dashboard
          </Typography>
          <Typography variant="subtitle1" color="text.secondary">
            Monitor document scanning statistics and history
          </Typography>
        </Box>
        <Box>
          <Tooltip title="Refresh statistics">
            <Button 
              variant="contained" 
              startIcon={<RefreshIcon />} 
              onClick={fetchStats}
              sx={{ mr: 1 }}
            >
              Refresh
            </Button>
          </Tooltip>
          <Tooltip title="Reset all statistics data">
            <Button 
              variant="outlined" 
              color="error" 
              startIcon={<DeleteIcon />} 
              onClick={resetStats}
            >
              Reset Stats
            </Button>
          </Tooltip>
        </Box>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      {loading ? (
        <Box sx={{ width: '100%' }}>
          <Grid container spacing={3}>
            {[1, 2, 3, 4].map((item) => (
              <Grid item xs={12} md={3} key={item}>
                <Skeleton variant="rectangular" height={120} animation="wave" />
              </Grid>
            ))}
            {[1, 2].map((item) => (
              <Grid item xs={12} md={6} key={`chart-${item}`}>
                <Skeleton variant="rectangular" height={300} animation="wave" />
              </Grid>
            ))}
            <Grid item xs={12}>
              <Skeleton variant="rectangular" height={400} animation="wave" />
            </Grid>
          </Grid>
        </Box>
      ) : stats ? (
        <Grid container spacing={3}>
          {/* Summary Cards */}
          <Grid item xs={12} md={3}>
            <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', height: 140, position: 'relative', overflow: 'hidden' }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <Typography variant="h6" color="primary" gutterBottom>
                  Total Scanned
                </Typography>
                <DescriptionIcon color="primary" sx={{ fontSize: 40, opacity: 0.2 }} />
              </Box>
              <Typography variant="h3" component="div" sx={{ mt: 2, fontWeight: 'bold' }}>
                {stats?.total_scanned || 0}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Documents processed
              </Typography>
              <Box sx={{ 
                position: 'absolute', 
                bottom: 0, 
                left: 0, 
                right: 0, 
                height: '4px', 
                bgcolor: 'primary.main' 
              }} />
            </Paper>
          </Grid>
          <Grid item xs={12} md={3}>
            <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', height: 140, position: 'relative', overflow: 'hidden' }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <Typography variant="h6" color="info.main" gutterBottom>
                  Passports
                </Typography>
                <PassportIcon color="info" sx={{ fontSize: 40, opacity: 0.2 }} />
              </Box>
              <Typography variant="h3" component="div" sx={{ mt: 2, fontWeight: 'bold' }}>
                {stats?.document_types?.passport || 0}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                {((stats?.document_types?.passport || 0) / (stats?.total_scanned || 1) * 100).toFixed(1)}% of total
              </Typography>
              <Box sx={{ 
                position: 'absolute', 
                bottom: 0, 
                left: 0, 
                right: 0, 
                height: '4px', 
                bgcolor: 'info.main' 
              }} />
            </Paper>
          </Grid>
          <Grid item xs={12} md={3}>
            <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', height: 140, position: 'relative', overflow: 'hidden' }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <Typography variant="h6" color="success.main" gutterBottom>
                  ID Cards
                </Typography>
                <BadgeIcon color="success" sx={{ fontSize: 40, opacity: 0.2 }} />
              </Box>
              <Typography variant="h3" component="div" sx={{ mt: 2, fontWeight: 'bold' }}>
                {stats?.document_types?.id_card || 0}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                {((stats?.document_types?.id_card || 0) / (stats?.total_scanned || 1) * 100).toFixed(1)}% of total
              </Typography>
              <Box sx={{ 
                position: 'absolute', 
                bottom: 0, 
                left: 0, 
                right: 0, 
                height: '4px', 
                bgcolor: 'success.main' 
              }} />
            </Paper>
          </Grid>
          <Grid item xs={12} md={3}>
            <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', height: 140, position: 'relative', overflow: 'hidden' }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <Typography variant="h6" color="warning.main" gutterBottom>
                  Countries
                </Typography>
                <PublicIcon color="warning" sx={{ fontSize: 40, opacity: 0.2 }} />
              </Box>
              <Typography variant="h3" component="div" sx={{ mt: 2, fontWeight: 'bold' }}>
                {stats?.nationalities ? Object.keys(stats.nationalities).length : 0}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Unique nationalities
              </Typography>
              <Box sx={{ 
                position: 'absolute', 
                bottom: 0, 
                left: 0, 
                right: 0, 
                height: '4px', 
                bgcolor: 'warning.main' 
              }} />
            </Paper>
          </Grid>

          {/* Charts */}
          <Grid item xs={12} md={6}>
            <Paper sx={{ 
              p: 2, 
              display: 'flex', 
              flexDirection: 'column', 
              height: 350,
              position: 'relative',
              overflow: 'hidden'
            }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                <Typography variant="h6" color="primary">
                  Document Types
                </Typography>
                <Chip 
                  label={`${stats?.document_types ? Object.keys(stats.document_types).length : 0} types`} 
                  size="small" 
                  color="primary" 
                  variant="outlined"
                />
              </Box>
              <Divider sx={{ mb: 2 }} />
              <Box sx={{ flexGrow: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {stats?.total_scanned > 0 ? (
                  <Pie 
                    data={documentTypeChartData} 
                    options={{ 
                      maintainAspectRatio: false,
                      plugins: {
                        legend: {
                          position: 'bottom',
                          labels: {
                            boxWidth: 15,
                            padding: 15
                          }
                        },
                        tooltip: {
                          callbacks: {
                            label: (context) => {
                              if (stats && stats.total_scanned) {
                                const label = context.label || '';
                                const value = context.raw || 0;
                                const percentage = ((value / stats.total_scanned) * 100).toFixed(1);
                                return `${label}: ${value} (${percentage}%)`;
                              }
                              return '';
                            }
                          }
                        }
                      }
                    }} 
                  />
                ) : (
                  <Box sx={{ textAlign: 'center', py: 5 }}>
                    <DescriptionIcon sx={{ fontSize: 60, color: 'text.disabled', mb: 2 }} />
                    <Typography variant="body1" color="text.secondary">
                      No documents scanned yet
                    </Typography>
                  </Box>
                )}
              </Box>
            </Paper>
          </Grid>
          <Grid item xs={12} md={6}>
            <Paper sx={{ 
              p: 2, 
              display: 'flex', 
              flexDirection: 'column', 
              height: 350,
              position: 'relative',
              overflow: 'hidden'
            }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                <Typography variant="h6" color="info.main">
                  Nationalities
                </Typography>
                <Tooltip title="Number of unique countries detected">
                  <Chip 
                    label={`${stats?.nationalities ? Object.keys(stats.nationalities).length : 0} countries`} 
                    size="small" 
                    color="info" 
                    variant="outlined"
                    icon={<PublicIcon sx={{ fontSize: '0.8rem' }} />}
                  />
                </Tooltip>
              </Box>
              <Divider sx={{ mb: 2 }} />
              <Box sx={{ flexGrow: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {stats?.nationalities && Object.keys(stats.nationalities).length > 0 ? (
                  <Bar 
                    data={nationalitiesChartData} 
                    options={{ 
                      maintainAspectRatio: false,
                      scales: {
                        y: {
                          beginAtZero: true,
                          ticks: {
                            precision: 0
                          }
                        }
                      },
                      plugins: {
                        legend: {
                          display: false
                        },
                        tooltip: {
                          callbacks: {
                            label: (context) => {
                              if (stats && stats.total_scanned) {
                                const label = context.dataset.label || '';
                                const value = context.raw || 0;
                                const percentage = ((value / stats.total_scanned) * 100).toFixed(1);
                                return `${label}: ${value} documents (${percentage}%)`;
                              }
                              return '';
                            }
                          }
                        }
                      }
                    }} 
                  />
                ) : (
                  <Box sx={{ textAlign: 'center', py: 5 }}>
                    <PublicIcon sx={{ fontSize: 60, color: 'text.disabled', mb: 2 }} />
                    <Typography variant="body1" color="text.secondary">
                      No nationality data available
                    </Typography>
                  </Box>
                )}
              </Box>
            </Paper>
          </Grid>

          {/* Scan History */}
          <Grid item xs={12}>
            <Paper sx={{ p: 2 }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
                <Box>
                  <Typography variant="h6" color="primary">
                    Scan History
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    {stats?.scan_history?.length || 0} {(stats?.scan_history?.length || 0) === 1 ? 'entry' : 'entries'} in total
                  </Typography>
                </Box>
                {stats?.scan_history?.length > 0 && (
                  <Tooltip title="Export scan history as CSV">
                    <IconButton 
                      color="primary"
                      size="small"
                      onClick={() => {
                        // Create CSV content
                        const headers = ['#', 'Timestamp', 'Document Type', 'Nationality'];
                        const csvContent = [
                          headers.join(','),
                          ...stats?.scan_history?.map((scan, index) => [
                            index + 1,
                            new Date(scan.timestamp).toLocaleString(),
                            scan.document_type.charAt(0).toUpperCase() + scan.document_type.slice(1),
                            scan.nationality
                          ].join(','))
                        ].join('\n');
                        
                        // Create download link
                        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
                        const url = URL.createObjectURL(blob);
                        const link = document.createElement('a');
                        link.setAttribute('href', url);
                        link.setAttribute('download', `scan_history_${new Date().toISOString().split('T')[0]}.csv`);
                        link.style.visibility = 'hidden';
                        document.body.appendChild(link);
                        link.click();
                        document.body.removeChild(link);
                      }}
                    >
                      <DownloadIcon />
                    </IconButton>
                  </Tooltip>
                )}
              </Box>
              <Divider sx={{ mb: 2 }} />
              <TableContainer sx={{ maxHeight: 400 }}>
                <Table stickyHeader>
                  <TableHead>
                    <TableRow>
                      <TableCell sx={{ fontWeight: 'bold' }}>#</TableCell>
                      <TableCell sx={{ fontWeight: 'bold' }}>Timestamp</TableCell>
                      <TableCell sx={{ fontWeight: 'bold' }}>Document Type</TableCell>
                      <TableCell sx={{ fontWeight: 'bold' }}>Nationality</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {stats?.scan_history?.length > 0 ? (
                      stats.scan_history.map((scan, index) => (
                        <TableRow 
                          key={index}
                          sx={{
                            '&:nth-of-type(odd)': { backgroundColor: 'rgba(0, 0, 0, 0.02)' },
                            '&:hover': { backgroundColor: 'rgba(0, 0, 0, 0.04)' },
                          }}
                        >
                          <TableCell>{index + 1}</TableCell>
                          <TableCell>
                            {new Date(scan.timestamp).toLocaleString()}
                            {index === 0 && (
                              <Chip 
                                label="Latest" 
                                color="primary" 
                                size="small" 
                                sx={{ ml: 1, height: 20 }} 
                              />
                            )}
                          </TableCell>
                          <TableCell>
                            <Box sx={{ display: 'flex', alignItems: 'center' }}>
                              {scan.document_type === 'passport' ? (
                                <PassportIcon fontSize="small" sx={{ mr: 1, color: 'info.main' }} />
                              ) : scan.document_type === 'id_card' ? (
                                <BadgeIcon fontSize="small" sx={{ mr: 1, color: 'success.main' }} />
                              ) : (
                                <DescriptionIcon fontSize="small" sx={{ mr: 1, color: 'warning.main' }} />
                              )}
                              {scan.document_type.charAt(0).toUpperCase() + scan.document_type.slice(1).replace('_', ' ')}
                            </Box>
                          </TableCell>
                          <TableCell>
                            <Box sx={{ display: 'flex', alignItems: 'center' }}>
                              <PublicIcon fontSize="small" sx={{ mr: 1, color: 'text.secondary' }} />
                              {scan.nationality}
                            </Box>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell colSpan={4} align="center" sx={{ py: 4 }}>
                          <Box sx={{ textAlign: 'center' }}>
                            <DescriptionIcon sx={{ fontSize: 40, color: 'text.disabled', mb: 1 }} />
                            <Typography variant="body1" color="text.secondary">
                              No scan history available
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                              Use the Scanner page to scan documents
                            </Typography>
                          </Box>
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </TableContainer>
            </Paper>
          </Grid>
        </Grid>
      ) : (
        <Typography variant="body1">No data available</Typography>
      )}
    </Container>
  );
};

export default Dashboard;
